features.snippet:
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    state <= StateReset;
  end else begin
    case (state)
      StateA: state <= StateB;
      StateB: state <= StateC;
      StateC: state <= StateA;
    endcase
  end
end

always_ff @(posedge clk) begin
  if (req) begin
    data <= a;
  end else if (ack) begin
    data <= b;
  end else begin
    data <= c;
  end
end

always_ff @(posedge clk) begin
  var1 <= next_var1;
  var2 <= next_var2;
  var3 <= next_var3;
  var4 <= next_var4;
end

always_comb begin
  next_state = state;
  case (state)
    4'b0000: if (cond0) next_state = 4'b0001;
    4'b0001: if (cond1) next_state = 4'b0010;
    4'b0010: if (cond2) next_state = 4'b0100;
    4'b0100: if (cond3) next_state = 4'b1000;
    default: next_state = 4'b0000;
  endcase
end
